"""Decode preserved icon SVGs from base64 and save to frontend/public/icons/.
Friend repo (jomebe/CrashZero @ b7b486f7) icons preserved as-is.
"""
import base64
import pathlib

ICONS = {
    "child-zone.svg": "",
    "crosswalk.svg": "",
    "median-barrier.svg": "",
    "traffic-cone.svg": "",
    "traffic-signal.svg": "",
    "road-risk.svg": "",
}

def main() -> None:
    out_dir = pathlib.Path("/data/crashzero/frontend/public/icons")
    out_dir.mkdir(parents=True, exist_ok=True)
    for name, b64 in ICONS.items():
        # base64 may include newlines from API response; strip them
        clean = "".join(b64.split())
        data = base64.b64decode(clean)
        target = out_dir / name
        target.write_bytes(data)
        print(f"wrote {name:24s} {len(data):>5d} bytes")


if __name__ == "__main__":
    main()
